from flask import redirect, session

def login_redirect():
    """
    Redirects users to their intended destination after authentication.

    Returns:
        A redirect response to the user's intended destination.
    """

    # Get the user's intended destination from the session.
    destination = session.get('destination')

    # If the user has an intended destination, redirect them there.
    if destination:
        return redirect(destination)

    # Otherwise, redirect the user to the home page.
    return redirect('/')